import axios from "axios";

const API_BASE_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    "Content-Type": "application/json",
  },
});

export const getRequest = (url, config = {}) => apiClient.get(url, config);
export const postRequest = (url, data = {}, config = {}) => apiClient.post(url, data, config);
export const putRequest = (url, data = {}, config = {}) => apiClient.put(url, data, config);

export const fetchCustomers = () => getRequest("/customers");
export const createCustomer = (payload) => postRequest("/customers", payload);
export const updateCustomerBalance = (customerId, payload) =>
  putRequest(`/customers/${customerId}/balance`, payload);

export default apiClient;
